query:
-- 为university_name添加索引
CREATE INDEX IF NOT EXISTS idx_professors_university ON professors(university_name(255));

-- 为department添加索引（指定长度）
CREATE INDEX IF NOT EXISTS idx_professors_department ON professors(department(255));

-- 为major_name添加索引
CREATE INDEX IF NOT EXISTS idx_professors_major ON professors(major_name(255));

-- 为university_name和major_name的组合添加复合索引（最常用的查询组合）
CREATE INDEX IF NOT EXISTS idx_professors_uni_major ON professors(university_name(255), major_name(255));

